// Example: Label a ConfigMap via OCP Console
// Generated by ftl:rhdp-lab-validator for UI steps
//
// Environment variables:
//   CONSOLE_URL  — OCP console URL (e.g. https://console-openshift-console.apps.cluster.example.com)
//   NAMESPACE    — target namespace
//   OCP_TOKEN    — bearer token (preferred)
//   USERNAME     — OCP username (fallback)
//   PASSWORD     — OCP password (fallback)
//   RESOURCE_KIND    — e.g. configmaps
//   RESOURCE_NAME    — e.g. lab-config
//   LABEL_KEY        — e.g. app
//   LABEL_VALUE      — e.g. lab

const { chromium } = require('playwright');

(async () => {
  const consoleUrl = process.env.CONSOLE_URL;
  const namespace  = process.env.NAMESPACE || 'default';
  const token      = process.env.OCP_TOKEN;
  const kind       = process.env.RESOURCE_KIND || 'configmaps';
  const name       = process.env.RESOURCE_NAME;
  const labelKey   = process.env.LABEL_KEY;
  const labelValue = process.env.LABEL_VALUE;

  if (!consoleUrl || !name || !labelKey) {
    console.error('FAILED: Missing required env vars (CONSOLE_URL, RESOURCE_NAME, LABEL_KEY)');
    process.exit(1);
  }

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ ignoreHTTPSErrors: true });
  const page    = await context.newPage();

  try {
    // Login via token if provided
    if (token) {
      await page.goto(`${consoleUrl}/api/v1/namespaces/${namespace}`, {
        extraHTTPHeaders: { Authorization: `Bearer ${token}` },
      });
    }

    await page.goto(consoleUrl);

    // Handle username/password login if needed
    if (!token) {
      const loginBtn = page.locator('a:has-text("Log in with OpenShift"),' +
        'button:has-text("Log in"), a:has-text("htpasswd"), a:has-text("OpenShift")');
      if (await loginBtn.count() > 0) {
        await loginBtn.first().click();
      }
      await page.fill('#inputUsername, [name="username"]', process.env.USERNAME || '');
      await page.fill('#inputPassword, [name="password"]', process.env.PASSWORD || '');
      await page.click('button[type="submit"]');
      await page.waitForURL(`${consoleUrl}/**`, { timeout: 15000 });
    }

    // Navigate to the resource
    await page.goto(`${consoleUrl}/k8s/ns/${namespace}/${kind}/${name}`);
    await page.waitForLoadState('networkidle');

    // Open Actions → Edit labels
    await page.click('[data-test-id="actions-menu-button"], button:has-text("Actions")');
    await page.click('text=Edit labels');
    await page.waitForSelector('[data-test="modal-title"], h1:has-text("Edit labels")');

    // Add the label
    const input = page.locator('input[placeholder*="label"], [data-test="labels-input"]');
    await input.fill(`${labelKey}=${labelValue}`);
    await page.keyboard.press('Enter');

    // Save
    await page.click('button:has-text("Save"), [data-test="confirm-action"]');
    await page.waitForSelector('.pf-m-success, [data-test="alert-success"]', { timeout: 10000 })
      .catch(() => {}); // success toast may not appear — that's ok

    console.log(`SUCCESS: ${kind}/${name} labeled ${labelKey}=${labelValue} in ${namespace}`);
    process.exit(0);
  } catch (err) {
    console.error(`FAILED: ${err.message}`);
    process.exit(1);
  } finally {
    await browser.close();
  }
})();
